// ============================================================
// WF09 — Health checks: iCal syncs + IMAP syncs
// Check sync_logs for each property, detect stale/error/never_synced
// IMAP sync logs read from Supabase node, iCal still via fetch
// ============================================================

const config = $('Config').first().json;
const propertiesRaw = $('HTTP: Get Active Properties').all().map(i => i.json);
const properties = Array.isArray(propertiesRaw[0]) ? propertiesRaw[0] : propertiesRaw;

const supabaseUrl = config.SUPABASE_URL;
const supabaseKey = config.SUPABASE_SERVICE_KEY;
const headers = {
  'apikey': supabaseKey,
  'Authorization': `Bearer ${supabaseKey}`
};

// --- Read IMAP sync logs from Supabase node ---
const imapSyncLogs = $('Supabase: Get IMAP Sync Logs').all().map(i => i.json);

const now = new Date();
const results = [];

// Thresholds (in milliseconds)
const ICAL_WARNING_MS = 60 * 60 * 1000;       // 1 hour
const ICAL_ERROR_MS = 2 * 60 * 60 * 1000;     // 2 hours
const IMAP_WARNING_MS = 5 * 60 * 1000;         // 5 minutes
const IMAP_ERROR_MS = 10 * 60 * 1000;          // 10 minutes

for (const property of properties) {
  if (!property.id) continue;

  const propResult = {
    property_id: property.id,
    property_name: property.name,
    owner_email: property.profiles ? property.profiles.email : null,
    owner_name: property.profiles ? property.profiles.display_name : null,
    ical_status: 'n/a',
    imap_status: 'n/a',
    last_ical_sync: null,
    last_imap_sync: null,
    issues: []
  };

  // --- Check iCal syncs ---
  if (property.ical_airbnb_url || property.ical_booking_url) {
    try {
      const icalRes = await fetch(
        `${supabaseUrl}/rest/v1/sync_logs?property_id=eq.${property.id}&source=like.ical_*&order=synced_at.desc&limit=5`,
        { headers }
      );
      const icalLogs = await icalRes.json();

      if (!icalLogs || icalLogs.length === 0) {
        propResult.ical_status = 'error';
        propResult.issues.push({ type: 'never_synced', severity: 'error', message: 'Aucune sync iCal enregistree' });
      } else {
        const lastSync = new Date(icalLogs[0].synced_at);
        propResult.last_ical_sync = icalLogs[0].synced_at;
        const ageMs = now - lastSync;

        // Check for consecutive errors
        const consecutiveErrors = icalLogs.filter(l => l.status === 'error').length;

        if (icalLogs[0].status === 'error') {
          propResult.ical_status = consecutiveErrors >= 3 ? 'error' : 'warning';
          propResult.issues.push({
            type: consecutiveErrors >= 3 ? 'persistent_error' : 'sync_error',
            severity: consecutiveErrors >= 3 ? 'error' : 'warning',
            message: `Derniere sync en erreur${consecutiveErrors >= 3 ? ` (${consecutiveErrors} erreurs consecutives)` : ''}`
          });
        } else if (ageMs > ICAL_ERROR_MS) {
          propResult.ical_status = 'error';
          propResult.issues.push({ type: 'stale_sync', severity: 'error', message: `Derniere sync iCal > 2 heures (${Math.round(ageMs / 60000)} min)` });
        } else if (ageMs > ICAL_WARNING_MS) {
          propResult.ical_status = 'warning';
          propResult.issues.push({ type: 'stale_sync', severity: 'warning', message: `Derniere sync iCal > 1 heure (${Math.round(ageMs / 60000)} min)` });
        } else {
          propResult.ical_status = 'ok';
        }
      }
    } catch (err) {
      propResult.ical_status = 'error';
      propResult.issues.push({ type: 'check_failed', severity: 'error', message: `Erreur verification iCal: ${err.message}` });
    }
  }

  // --- Check IMAP syncs ---
  // IMAP is global, not per-property — check once using data from Supabase node
  if (property === properties[0]) {
    if (imapSyncLogs && imapSyncLogs.length > 0) {
      const lastImapSync = new Date(imapSyncLogs[0].synced_at);
      const imapAgeMs = now - lastImapSync;

      const imapErrors = imapSyncLogs.filter(l => l.status === 'error').length;

      if (imapSyncLogs[0].status === 'error' && imapErrors >= 5) {
        propResult.imap_status = 'error';
        propResult.issues.push({ type: 'imap_error', severity: 'error', message: `IMAP en erreur (${imapErrors} erreurs consecutives)` });
      } else if (imapAgeMs > IMAP_ERROR_MS) {
        propResult.imap_status = 'error';
        propResult.issues.push({ type: 'stale_imap', severity: 'error', message: `Derniere sync IMAP > 10 min (${Math.round(imapAgeMs / 60000)} min)` });
      } else if (imapAgeMs > IMAP_WARNING_MS) {
        propResult.imap_status = 'warning';
        propResult.issues.push({ type: 'stale_imap', severity: 'warning', message: `Derniere sync IMAP > 5 min (${Math.round(imapAgeMs / 60000)} min)` });
      } else {
        propResult.imap_status = 'ok';
      }

      propResult.last_imap_sync = imapSyncLogs[0].synced_at;
    }
  }

  results.push(propResult);
}

// Aggregate
const totalProperties = results.length;
const healthy = results.filter(r => r.issues.length === 0).length;
const withWarnings = results.filter(r => r.issues.some(i => i.severity === 'warning') && !r.issues.some(i => i.severity === 'error')).length;
const withErrors = results.filter(r => r.issues.some(i => i.severity === 'error')).length;

return [{
  json: {
    total_properties: totalProperties,
    healthy: healthy,
    warnings: withWarnings,
    errors: withErrors,
    has_issues: withWarnings > 0 || withErrors > 0,
    details: results,
    checked_at: now.toISOString()
  }
}];

// ============================================================
// WF09 — Build health check alert email
// ============================================================

const config = $('Config').item.json;
const data = $input.item.json;

const statusColors = {
  'ok': '#22c55e',
  'warning': '#f59e0b',
  'error': '#dc2626',
  'n/a': '#9ca3af'
};

const statusLabels = {
  'ok': 'OK',
  'warning': 'Warning',
  'error': 'Erreur',
  'n/a': 'N/A'
};

const statusDot = (status) => {
  const color = statusColors[status] || '#9ca3af';
  return `<span style="display:inline-block;width:10px;height:10px;border-radius:50%;background:${color};margin-right:4px;"></span>${statusLabels[status] || status}`;
};

let html = `<div style="font-family:-apple-system,sans-serif;max-width:600px;margin:0 auto;">`;
html += `<div style="background:#1a1a2e;color:#fff;padding:16px;border-radius:8px 8px 0 0;">`;
html += `<h2 style="margin:0;">Health Check — ${data.errors} erreur(s), ${data.warnings} warning(s)</h2>`;
html += `<p style="margin:4px 0 0 0;opacity:0.8;">${new Date(data.checked_at).toLocaleString('fr-FR', { timeZone: 'Europe/Paris' })}</p>`;
html += `</div>`;
html += `<div style="padding:16px;">`;

// KPIs
html += `<div style="display:flex;justify-content:space-around;margin-bottom:16px;padding:12px;background:#f3f4f6;border-radius:8px;text-align:center;">`;
html += `<div><strong style="font-size:24px;color:#22c55e;">${data.healthy}</strong><br><small>Sain(s)</small></div>`;
html += `<div><strong style="font-size:24px;color:#f59e0b;">${data.warnings}</strong><br><small>Warning(s)</small></div>`;
html += `<div><strong style="font-size:24px;color:#dc2626;">${data.errors}</strong><br><small>Erreur(s)</small></div>`;
html += `</div>`;

// Table details
html += `<table style="width:100%;border-collapse:collapse;font-size:14px;">`;
html += `<tr style="background:#1a1a2e;color:#fff;">`;
html += `<th style="padding:8px;text-align:left;">Propriete</th>`;
html += `<th style="padding:8px;text-align:left;">Owner</th>`;
html += `<th style="padding:8px;text-align:center;">iCal</th>`;
html += `<th style="padding:8px;text-align:center;">IMAP</th>`;
html += `</tr>`;

for (const prop of data.details) {
  if (prop.issues.length === 0) continue;

  const bgColor = prop.issues.some(i => i.severity === 'error') ? '#fef2f2' :
                  prop.issues.some(i => i.severity === 'warning') ? '#fffbeb' : '#fff';

  html += `<tr style="background:${bgColor};border-bottom:1px solid #e5e7eb;">`;
  html += `<td style="padding:8px;">${prop.property_name}</td>`;
  html += `<td style="padding:8px;">${prop.owner_name || '-'}</td>`;
  html += `<td style="padding:8px;text-align:center;">${statusDot(prop.ical_status)}</td>`;
  html += `<td style="padding:8px;text-align:center;">${statusDot(prop.imap_status)}</td>`;
  html += `</tr>`;

  for (const issue of prop.issues) {
    html += `<tr style="background:#f9fafb;"><td colspan="4" style="padding:4px 8px 4px 24px;font-size:12px;color:${statusColors[issue.severity]};">`;
    html += `${issue.message}`;
    html += `</td></tr>`;
  }
}

html += `</table>`;
html += `</div></div>`;

const subject = `[Neurolia-Immo] Health Check — ${data.errors} erreur(s), ${data.warnings} warning(s)`;

return [{
  json: {
    subject: subject,
    html: html
  }
}];
